// Tasks are executable orchestration items.
// The playground runs task main() -> u32 and reports the exit value.
task main() -> u32 {
    exit 42;
}

// forever repeats bounded task work until the task exits.
// This example is finite: the loop reaches exit 42.
task main() -> u32 {
    let mut value: u32 = 0;

    forever {
        if value == 42 {
            exit value;
        }

        value = value + 1 or(err) 0;
    }
}

// delegate transfers control to another task instead of returning.
// The worker task receives the value and exits the program.
task main() -> u32 {
    delegate worker(42);
}

task worker(value: u32) -> u32 {
    exit value;
}

// Cyclic delegation is bounded because delegate replaces task state.
// count delegates to itself until the countdown reaches zero.
task main() -> u32 {
    delegate count(3);
}

task count(value: u32) -> u32 {
    if value == 0 {
        exit 42;
    } else {
        delegate count(value - 1 or(err) 0);
    }
}

// Delegate arguments are evaluated before the caller state is replaced.
// swap(second, first) exits with the original first value after one transfer.
task main() -> u32 {
    delegate swap(7, 42);
}

task swap(first: u32, second: u32) -> u32 {
    if first == 42 {
        exit second;
    } else {
        delegate swap(second, first);
    }
}

// Functions are total helpers that tasks can call.
// Calls are direct: scale_then_add(6, 7) returns 42.
fn scale_then_add(left: u32, right: u32) -> u32 {
    left * right or(err) 0
}

task main() -> u32 {
    exit scale_then_add(6, 7);
}

// let introduces bindings. mut allows assignment.
// Blocks can produce values with a trailing expression.
task main() -> u32 {
    let start: u32 = 10;
    let mut total: u32 = start;

    total = {
        let bonus: u32 = 32;
        total + bonus or(err) 0
    };

    exit total;
}

// read_u32 consumes one token from stdin.
// print_u32, print_bool, and print_newline write to the terminal.
task main() -> u32 {
    let value: u32 = read_u32();
    let doubled: u32 = value * 2 or(err) 0;

    print_u32(doubled);
    print_newline();
    print_bool(doubled > value);
    print_newline();

    exit doubled;
}

// if is a statement. Conditions are bool values.
// Comparisons, &&, ||, and exit are supported in tasks.
task main() -> u32 {
    let value: u32 = 42;

    if (value > 10 && value < 100) || value == 7 {
        exit value;
    }

    exit 0;
}

// match supports literal, wildcard, and binding patterns.
fn choose(flag: bool, code: u32) -> u32 {
    let mut value: u32 = 0;

    match flag {
        true => { value = 10; },
        false => { value = 20; }
    }

    match code {
        0 => { value = value + 1 or(err) 0; },
        7 => { value = value + 32 or(err) 0; },
        _ => { value = value + code or(err) 0; }
    }

    value
}

task main() -> u32 {
    exit choose(true, 7);
}

// Ordinary u32 arithmetic returns Result<u32, ArithmeticError>.
// Use or(err) to recover and inspect failures explicitly.
task main() -> u32 {
    let added: u32 = 40 + 2 or(err) 0;
    let subtracted: u32 = 50 - 8 or(err) 0;
    let multiplied: u32 = 6 * 7 or(err) 0;
    let divided: u32 = 84 / 2 or(err) 0;
    let remainder: u32 = 85 % 43 or(err) 0;

    let mut failures: u32 = 0;

    4294967295 + 1 or(err) {
        if err == arithmetic_overflow() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    0 - 1 or(err) {
        if err == arithmetic_underflow() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    1 / 0 or(err) {
        if err == divide_by_zero() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    1 % 0 or(err) {
        if err == remainder_by_zero() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    if added == 42 && subtracted == 42 && multiplied == 42 && divided == 42 && remainder == 42 && failures == 4 {
        exit 42;
    }

    exit 0;
}

// Option<T> is either some(value) or none().
// Recovery uses the fallback only for none().
task main() -> u32 {
    let present: Option<u32> = some(40);
    let missing: Option<u32> = none();

    let left: u32 = present or 0;
    let right: u32 = missing or 2;

    exit left + right or(err) 0;
}

// Result<T, E> is ok(value) or err(error).
// Result recovery can bind the error payload.
fn parse_like(flag: bool) -> Result<u32, bool> {
    if flag {
        return ok(40);
    }

    err(true)
}

task main() -> u32 {
    let recovered: u32 = parse_like(false) or(failed) {
        if failed {
            exit 42;
        }
        0
    };

    exit recovered;
}

// Tuples can be passed, returned, and compared structurally.
fn pair(value: u32, flag: bool) -> (u32, bool) {
    (value, flag)
}

task main() -> u32 {
    let actual: (u32, bool) = pair(42, true);
    let expected: (u32, bool) = (42, true);

    if actual == expected && actual != (0, false) {
        exit 42;
    }

    exit 0;
}

// Fixed arrays support constant and dynamic indexing.
// observe proves that a dynamic index is in bounds.
task main() -> u32 {
    let values: [u32; 4] = [10, 20, 30, 40];
    let index: u32 = 2;

    observe index < 4 else {
        exit 0;
    }

    exit values[0] + values[index] or(err) 0;
}

// Arrays can contain flattened aggregate values like tuples.
// Structural equality works on indexed aggregate elements.
task main() -> u32 {
    let pairs: [(u32, bool); 2] = [(10, false), (42, true)];
    let index: u32 = 1;

    observe index < 2 else {
        exit 0;
    }

    if pairs[index] == (42, true) {
        exit 42;
    }

    exit 0;
}

// for loops over fixed arrays are bounded.
// Checked arithmetic still needs recovery inside the loop.
task main() -> u32 {
    let values: [u32; 4] = [9, 10, 11, 12];
    let mut total: u32 = 0;

    for value in values {
        total = total + value or(err) 0;
    }

    exit total;
}

// Ranges are start-inclusive and end-exclusive.
// A range can be bound and reused as the loop iterable.
task main() -> u32 {
    let range = 0..7;
    let mut total: u32 = 0;

    for value in range {
        total = total + value or(err) 0;
    }

    exit total * 2 or(err) 0;
}

// observe records a fact and runs else only if the fact is false.
// The proof checker can use the fact to accept the dynamic index.
task main() -> u32 {
    let values: [u32; 4] = [10, 20, 30, 42];
    let index: u32 = 3;

    observe index < 4 else {
        exit 0;
    }

    exit values[index];
}

// Markers are compile-time facts attached to value places.
// This example creates a custom Trusted marker and carries it through a function boundary.
marker Trusted();

fn accept(value: u32 with Trusted) -> u32 with Trusted {
    return value;
}

task main() -> u32 {
    let raw: u32 = 42;
    let marked: u32 with Trusted = unsafe { Trusted::mark(raw) };
    let copied: u32 with Trusted = marked;

    exit accept(copied);
}

// User marker families can appear in companion rules.
// The Sub rule below preserves UpperBound(value, bound) facts through successful subtraction.
marker UpperBound(value: place, bound: place);

mark Sub(a: place, amount: place, result: place) {
    if a with UpperBound(a, ?bound) {
        implies UpperBound(result, bound) for result;
    }
}

fn keep_upper_bound(value: u32 with UpperBound(4)) -> u32 with UpperBound(4) {
    return value;
}

task main() -> u32 {
    let index: u32 with UpperBound(4) = unsafe { UpperBound::mark(3, 4) };
    let fallback: u32 with UpperBound(4) = unsafe { UpperBound::mark(0, 4) };
    let smaller: u32 with UpperBound(4) = index - 1 or(err) fallback;

    exit keep_upper_bound(smaller) + 40 or(err) 0;
}
